// Extract fields from Linear webhook payload
const evt  = $input.first().json || {};

// Only process Issue and Comment events
if (evt.type && evt.type !== 'Issue' && evt.type !== 'Comment') {
  return [];
}

const d    = evt.data      || {};
const team = d.team      || {};

// Labels arrive as an array of {id, name} objects on update events
const labels = (d.labels || []).map(l => (l.name || '').toLowerCase());

return [{
  json: {
    type:         evt.type     || '',
    action:      evt.action   || '',
    issue_id:    d.identifier || '',
    issue_uuid:  d.id         || '',
    title:       d.title     || '',
    description: d.body      || d.description || '',
    url:         d.url       || evt.url || '',
    priority:    d.priority  ?? null,
    labels:      labels,
    team_id:     team.id    || '',
    team_key:    team.key   || '',
    received_at: new Date().toISOString()
  }
}];

const labels = ($json.labels || []).map(l => typeof l === 'string' ? l.toLowerCase() : ((l.name || '')).toLowerCase());
const action = ($json.action || '').toLowerCase();
const eventType = ($json.type || '').toLowerCase();

// Handle Comment events - extract issue reference from comment
if (eventType === 'comment') {
  const commentBody = $json.description || '';
  const issueId = $json.issue_id || '';
  const issueUuid = $json.issue_uuid || '';

  // Only process if comment is from a user (not bot) and has content
  if (commentBody && (issueId || issueUuid)) {
    return [{
      json: {
        issue_id: issueId,
        issue_uuid: issueUuid,
        title: `Comment on ${issueId}`,
        description: commentBody,
        phase: 'implement',
        repo: 'thanhnhan2tn/mini-dev-station',
        team_id: $json.team_id || '',
        labels: ['comment', 'implement'],
        url: $json.url || ''
      }
    }];
  }
  return [];
}

// Skip if no matching action/labels for Issues
const shouldProcess = labels.includes('plan') || labels.includes('implement');
if (!shouldProcess) {
  return [];
}

// Default new issues to 'plan' phase unless labeled 'implement'
let phase = 'plan';
if (labels.includes('implement')) {
  phase = 'implement';
}

const esc = s => (s || '').replace(/'/g, "'\\''");

return [{
  json: {
    issue_id: $json.issue_id || '',
    issue_uuid: $json.issue_uuid || '',
    title: $json.title || '',
    description: esc($json.description || ''),
    phase: phase,
    repo: 'thanhnhan2tn/mini-dev-station',
    team_id: $json.team_id || '',
    labels: labels,
    url: $json.url || ''
  }
}];

// Format pipeline result for Linear.
// Both `plan` and `implement` phases include a `plan_url` referencing
// docs/plans/{issue_id}.md so the implement step can link back to the
// plan generated by the prior plan step.
const response = $input.first().json || {};
const parseData = $('Parse Issue + Labels').first().json;
const issueId = parseData?.issue_id || 'Unknown';
const phase = response.phase || parseData?.phase || 'N/A';
const status = response.status;

const lines = [];
if (status === 'ok') {
  if (phase === 'plan') {
    lines.push(`🤖 AI Dev Station — *${issueId}* — Plan complete`);
  } else if (phase === 'implement') {
    lines.push(`🤖 AI Dev Station — *${issueId}* — Implementation complete`);
  } else {
    lines.push(`🤖 AI Dev Station processed *${issueId}*`);
  }
  lines.push('');
  if (response.plan_url) {
    lines.push(`📋 Plan doc: ${response.plan_url}`);
  }
  lines.push(`🔗 PR: ${response.pr_url || 'pending'}`);
  if (phase === 'implement') {
    lines.push(`✅ Verdict: ${response.verdict || 'N/A'}`);
  }
} else {
  const errorMsg = response.error || response.message || JSON.stringify(response);
  lines.push(`❌ AI Dev Station failed for *${issueId}*`);
  lines.push('');
  if (response.plan_url) {
    lines.push(`📋 Plan doc: ${response.plan_url}`);
  }
  lines.push(`Error: ${errorMsg}`);
}

const body = lines.join('\n');

return { json: { issueUuid: parseData?.issue_uuid, body } };
